from pymilvus import MilvusClient

client = MilvusClient(uri='http://localhost:19530')

# TRIE index: best for string equality/prefix filters
client.create_index(
    collection_name='articles',
    index_params={
        'field_name': 'source',
        'index_type': 'TRIE',
    }
)

# BITMAP index: best for low-cardinality fields (< 500 distinct values)
client.create_index(
    collection_name='articles',
    index_params={
        'field_name': 'category',
        'index_type': 'BITMAP',
    }
)

# STL_SORT: range queries on numeric fields
client.create_index(
    collection_name='articles',
    index_params={
        'field_name': 'published_year',
        'index_type': 'STL_SORT',
    }
)
